#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;

    vector<int> startTime(n), endTime(n), profit(n);
    vector<tuple<int, int, int>> jobs(n);

    // Input
    for(int i = 0; i < n; i++) 
        cin >> startTime[i];
    for(int i = 0; i < n; i++) 
        cin >> endTime[i];
    for(int i = 0; i < n; i++) 
        cin >> profit[i];

    // Create jobs array sorted by end time
    for(int i = 0; i < n; i++) {
        jobs[i] = {endTime[i], startTime[i], profit[i]};
    }
    sort(jobs.begin(), jobs.end());

    // dp[i] represents maximum profit we can make till index i
    vector<int> dp(n + 1, 0);

    for(int i = 0; i < n; i++) {
        auto [end, start, prof] = jobs[i];

        // Find rightmost job that doesn't conflict with current job
        int lastNonConflict = upper_bound(
            jobs.begin(), 
            jobs.begin() + i, 
            start,
            [&](int time, const auto& job) {
                return time < get<0>(job);
            }
        ) - jobs.begin();

        // Either include current job or exclude it
        dp[i + 1] = max(dp[i], dp[lastNonConflict] + prof);
    }

    cout << dp[n] << "\n";
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        solve();
    }
    return 0;
}
